package pe.edu.utp.tmo.util; import java.security.SecureRandom; import java.time.*; import java.time.format.DateTimeFormatter; import org.springframework.stereotype.Component; @Component public class TicketCodeGenerator{private final SecureRandom r=new SecureRandom(); private final Clock c; public TicketCodeGenerator(Clock c){this.c=c;} public String nuevoCodigo(){return "TMO-"+LocalDate.now(c).format(DateTimeFormatter.BASIC_ISO_DATE)+"-"+(r.nextInt(900000)+100000);}}